1	type Item = { type: string; material?: string; cursed?: boolean; enchantment?: number };
2	type Damage = { itemType: string; amount: number };
3	type Incident = { cause: string; damages: Damage[] };
4	type QuoteStep = { op: "quote"; items: Item[] };
5	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	type Step = QuoteStep | ClaimStep;
7	type Customer = { yearsWithMHPCO: number };
8	type Input = { customer: Customer; steps: Step[] };
9	
10	const PROCESSING_FEE = 5;
11	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
12	const CURSE_SURCHARGE_PERCENT = 50;
13	const HIGH_ENCHANTMENT_THRESHOLD = 5;
14	const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
15	const LOYALTY_THRESHOLD_YEARS = 2;
16	const LOYALTY_DISCOUNT_PERCENT = 20;
17	const FOLLOWUP_CONTRACT_DISCOUNT_PERCENT = 15;
18	const COMPONENT_BLOCK_SIZE = 3;
19	const COMPONENT_BLOCK_PREMIUM = 60;
20	const DEDUCTIBLE = 100;
21	const CAP_MULTIPLIER = 2;
22	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
23	const HIGH_ENCHANTMENT_CLAIM_PERCENT = 50;
24	
25	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
26	  sword: 1000,
27	  amulet: 600,
28	  staff: 800,
29	  potion: 400,
30	  rune: 250,
31	  moonstone: 250,
32	};
33	
34	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
35	  sword: 100,
36	  amulet: 60,
37	  staff: 80,
38	  potion: 40,
39	  rune: 25,
40	  moonstone: 25,
41	};
42	
43	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
44	
45	const groupBaseAmount = (type: string, count: number): number => {
46	  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
47	    return COMPONENT_BLOCK_PREMIUM;
48	  }
49	  return count * BASE_PREMIUM_BY_TYPE[type];
50	};
51	
52	const countByType = (items: Item[]): Map<string, number> =>
53	  items.reduce(
54	    (counts, { type }) => counts.set(type, (counts.get(type) ?? 0) + 1),
55	    new Map<string, number>(),
56	  );
57	
58	const basePremium = (items: Item[]): number =>
59	  Array.from(countByType(items)).reduce(
60	    (total, [type, count]) => total + groupBaseAmount(type, count),
61	    0,
62	  );
63	
64	const percentOf = (amount: number, percent: number): number =>
65	  (amount * percent) / 100;
66	
67	const percentOfItemBase = (item: Item, percent: number): number =>
68	  percentOf(BASE_PREMIUM_BY_TYPE[item.type], percent);
69	
70	const firstInsuranceSurcharge = (base: number): number =>
71	  percentOf(base, FIRST_INSURANCE_SURCHARGE_PERCENT);
72	
73	const enchantmentAtLeast = (item: Item, threshold: number): boolean =>
74	  (item.enchantment ?? 0) >= threshold;
75	
76	type ItemSurchargeRule = { applies: (item: Item) => boolean; percent: number };
77	
78	const ITEM_SURCHARGE_RULES: ItemSurchargeRule[] = [
79	  { applies: (item) => item.cursed === true, percent: CURSE_SURCHARGE_PERCENT },
80	  { applies: (item) => enchantmentAtLeast(item, HIGH_ENCHANTMENT_THRESHOLD), percent: HIGH_ENCHANTMENT_SURCHARGE_PERCENT },
81	];
82	
83	const surchargesForItem = (item: Item): number =>
84	  ITEM_SURCHARGE_RULES.reduce(
85	    (sum, { applies, percent }) => sum + (applies(item) ? percentOfItemBase(item, percent) : 0),
86	    0,
87	  );
88	
89	const itemSurcharges = (items: Item[]): number =>
90	  items.reduce((sum, item) => sum + surchargesForItem(item), 0);
91	
92	type PolicyContext = { customer: Customer; stepIndex: number };
93	type PolicyDiscountRule = { applies: (ctx: PolicyContext) => boolean; percent: number };
94	
95	const POLICY_DISCOUNT_RULES: PolicyDiscountRule[] = [
96	  { applies: ({ customer }) => customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS, percent: LOYALTY_DISCOUNT_PERCENT },
97	  { applies: ({ stepIndex }) => stepIndex > 0, percent: FOLLOWUP_CONTRACT_DISCOUNT_PERCENT },
98	];
99	
100	const policyDiscounts = (base: number, ctx: PolicyContext): number =>
101	  POLICY_DISCOUNT_RULES.reduce(
102	    (sum, { applies, percent }) => sum + (applies(ctx) ? percentOf(base, percent) : 0),
103	    0,
104	  );
105	
106	const quotePremium = (items: Item[], ctx: PolicyContext): number => {
107	  const base = basePremium(items);
108	  const surcharges = itemSurcharges(items) + firstInsuranceSurcharge(base);
109	  const discounts = policyDiscounts(base, ctx);
110	  return Math.ceil(base + surcharges - discounts + PROCESSING_FEE);
111	};
112	
113	const insuranceSum = (items: Item[]): number =>
114	  items.reduce((sum, { type }) => sum + INSURANCE_VALUE_BY_TYPE[type], 0);
115	
116	const policyCap = (items: Item[]): number => CAP_MULTIPLIER * insuranceSum(items);
117	
118	const reimbursableAmount = (amount: number, item: Item): number =>
119	  enchantmentAtLeast(item, HIGH_ENCHANTMENT_CLAIM_THRESHOLD)
120	    ? percentOf(amount, HIGH_ENCHANTMENT_CLAIM_PERCENT)
121	    : amount;
122	
123	const damagePayout = (amount: number, item: Item): number =>
124	  Math.max(0, reimbursableAmount(amount, item) - DEDUCTIBLE);
125	
126	const findInsuredItem = (items: Item[], itemType: string): Item => {
127	  const item = items.find((i) => i.type === itemType);
128	  if (!item) throw new Error(`item type ${itemType} not in policy`);
129	  return item;
130	};
131	
132	const totalRequestedPayout = (damages: Damage[], items: Item[]): number =>
133	  damages.reduce(
134	    (sum, { itemType, amount }) => sum + damagePayout(amount, findInsuredItem(items, itemType)),
135	    0,
136	  );
137	
138	type Policy = { items: Item[]; remainingCap: number };
139	
140	type StepResult = { premium: number } | { payout: number; remainingCap: number };
141	
142	const processQuote = (step: QuoteStep, ctx: PolicyContext, policies: Policy[]): StepResult => {
143	  policies.push({ items: step.items, remainingCap: policyCap(step.items) });
144	  return { premium: quotePremium(step.items, ctx) };
145	};
146	
147	const processClaim = (step: ClaimStep, policies: Policy[]): StepResult => {
148	  const policy = policies[step.policy];
149	  const cappedPayout = Math.min(totalRequestedPayout(step.incident.damages, policy.items), policy.remainingCap);
150	  policy.remainingCap -= cappedPayout;
151	  return { payout: Math.floor(cappedPayout), remainingCap: policy.remainingCap };
152	};
153	
154	export const run = (input: unknown): unknown => {
155	  const { customer, steps } = input as Input;
156	  const policies: Policy[] = [];
157	  const results = steps.map((step, stepIndex): StepResult =>
158	    step.op === "quote"
159	      ? processQuote(step, { customer, stepIndex }, policies)
160	      : processClaim(step, policies),
161	  );
162	  return { results };
163	};
